import React, { useState } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { Shield, Bell, Settings, Globe, LogOut, Menu, X, Activity } from 'lucide-react';

export default function Navbar({ lang, onLangToggle }) {
  const navigate = useNavigate();
  const location = useLocation();
  const [notifOpen, setNotifOpen] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  const navLinks = [
    { path: '/dashboard', label: 'Dashboard', icon: <Activity className="w-4 h-4" /> },
    { path: '/analyzer', label: 'Analyzer', icon: <Shield className="w-4 h-4" /> },
    { path: '/encyclopedia', label: 'Encyclopedia', icon: <Globe className="w-4 h-4" /> },
  ];

  return (
    <nav className="sticky top-0 z-50 w-full border-b border-white/10 bg-[#050B18]/80 backdrop-blur-lg">
      <div className="max-w-[1600px] mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-16 md:h-20">
          
          {/* Logo */}
          <div className="flex-shrink-0">
            <Link to="/" className="flex items-center gap-3 group">
              <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-emerald-400 to-cyan-500 p-0.5 group-hover:shadow-[0_0_20px_rgba(16,185,129,0.4)] transition-all duration-300">
                <div className="w-full h-full bg-[#050B18] rounded-[10px] flex items-center justify-center">
                  <Shield className="w-5 h-5 text-emerald-400" />
                </div>
              </div>
              <div className="hidden sm:block">
                <div className="font-black text-xl tracking-tight text-white flex items-center gap-1">
                  Cyber<span className="text-emerald-400">Guard</span>
                  <span className="text-cyan-400 font-bold text-sm bg-cyan-400/10 px-1.5 py-0.5 rounded ml-1">AI</span>
                </div>
                <div className="text-[9px] font-bold tracking-[0.2em] text-gray-500 uppercase mt-0.5">
                  Threat Intelligence
                </div>
              </div>
            </Link>
          </div>

          {/* Desktop Nav Links */}
          <div className="hidden md:flex items-center space-x-1 lg:space-x-2 bg-white/[0.02] p-1.5 rounded-2xl border border-white/5">
            {navLinks.map(link => {
              const active = location.pathname === link.path;
              return (
                <Link
                  key={link.path}
                  to={link.path}
                  className={`flex items-center gap-2 px-4 py-2.5 rounded-xl text-sm font-semibold transition-all duration-300 ${
                    active 
                      ? 'bg-white/10 text-white shadow-sm' 
                      : 'text-gray-400 hover:text-gray-200 hover:bg-white/5'
                  }`}
                >
                  <span className={`${active ? 'text-emerald-400' : 'text-gray-500'}`}>{link.icon}</span>
                  {link.label}
                </Link>
              );
            })}
          </div>

          {/* Right Controls */}
          <div className="flex items-center gap-2 sm:gap-4">
            
            {/* Language Toggle */}
            <button 
              onClick={onLangToggle}
              className="hidden sm:flex items-center gap-2 px-3 py-2 rounded-xl text-sm font-medium text-gray-300 hover:text-white hover:bg-white/5 transition-colors border border-transparent hover:border-white/10"
            >
              <Globe className="w-4 h-4 text-gray-400" />
              <span>{lang === 'en' ? 'हिन्दी' : 'EN'}</span>
            </button>

            {/* Notifications */}
            <div className="relative">
              <button 
                onClick={() => setNotifOpen(!notifOpen)}
                className="relative p-2.5 rounded-xl text-gray-400 hover:text-white hover:bg-white/5 transition-colors"
              >
                <Bell className="w-5 h-5" />
                <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full border border-[#050B18] animate-pulse"></span>
              </button>

              {/* Dropdown */}
              {notifOpen && (
                <div className="absolute right-0 mt-2 w-80 bg-[#0A1128] border border-white/10 rounded-2xl shadow-2xl py-2 z-50 animate-[fadeIn_0.2s_ease-out]">
                  <div className="px-4 py-3 border-b border-white/5 flex items-center justify-between">
                    <h3 className="text-sm font-bold text-white">Notifications</h3>
                    <span className="text-xs bg-red-500/10 text-red-400 px-2 py-0.5 rounded-md font-bold">3 New</span>
                  </div>
                  <div className="max-h-[300px] overflow-y-auto p-2">
                    {[
                      { icon: '🚨', msg: 'New phishing campaign detected', time: '2m ago', type: 'danger' },
                      { icon: '⚠️', msg: 'High-risk URL flagged in SMS', time: '15m ago', type: 'warning' },
                      { icon: '✅', msg: 'Weekly threat scan complete', time: '1h ago', type: 'success' },
                    ].map((n, i) => (
                      <div key={i} className="flex gap-3 items-start p-3 hover:bg-white/5 rounded-xl transition-colors cursor-pointer mb-1">
                        <span className="text-xl leading-none">{n.icon}</span>
                        <div className="flex-1">
                          <p className="text-sm font-medium text-gray-200 mb-0.5">{n.msg}</p>
                          <p className="text-xs text-gray-500 font-medium">{n.time}</p>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>

            {/* Settings */}
            <button className="hidden sm:block p-2.5 rounded-xl text-gray-400 hover:text-white hover:bg-white/5 transition-colors">
              <Settings className="w-5 h-5" />
            </button>

            <div className="hidden sm:block w-px h-8 bg-white/10 mx-1"></div>

            {/* Auth Button */}
            {localStorage.getItem('isAuthenticated') === 'true' ? (
              <button 
                onClick={() => { localStorage.removeItem('isAuthenticated'); navigate('/login'); }}
                className="hidden sm:flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-bold text-red-400 hover:text-red-300 hover:bg-red-500/10 transition-colors border border-transparent hover:border-red-500/20"
              >
                <LogOut className="w-4 h-4" />
                Sign Out
              </button>
            ) : (
              <Link 
                to="/login"
                className="hidden sm:flex items-center justify-center px-5 py-2 rounded-xl text-sm font-bold text-[#050B18] bg-gradient-to-r from-emerald-400 to-cyan-500 hover:brightness-110 transition-all shadow-[0_0_15px_rgba(16,185,129,0.3)]"
              >
                Sign In
              </Link>
            )}

            {/* Mobile Menu Button */}
            <button 
              className="md:hidden p-2 rounded-xl text-gray-400 hover:text-white hover:bg-white/5 transition-colors"
              onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
            >
              {mobileMenuOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
            </button>

          </div>
        </div>
      </div>

      {/* Mobile Menu Dropdown */}
      {mobileMenuOpen && (
        <div className="md:hidden border-t border-white/10 bg-[#0A1128] absolute w-full">
          <div className="px-4 py-4 flex flex-col gap-2">
            {navLinks.map(link => {
              const active = location.pathname === link.path;
              return (
                <Link
                  key={link.path}
                  to={link.path}
                  onClick={() => setMobileMenuOpen(false)}
                  className={`flex items-center gap-3 px-4 py-3 rounded-xl text-base font-semibold transition-all ${
                    active 
                      ? 'bg-white/10 text-white' 
                      : 'text-gray-400 hover:text-white hover:bg-white/5'
                  }`}
                >
                  <span className={`${active ? 'text-emerald-400' : 'text-gray-500'}`}>{link.icon}</span>
                  {link.label}
                </Link>
              );
            })}
            
            <div className="h-px bg-white/10 my-2"></div>
            
            <button 
              onClick={onLangToggle}
              className="flex items-center gap-3 px-4 py-3 rounded-xl text-base font-semibold text-gray-400 hover:text-white hover:bg-white/5 transition-all"
            >
              <Globe className="w-5 h-5 text-gray-500" />
              Language: {lang === 'en' ? 'EN' : 'हिन्दी'}
            </button>

            {localStorage.getItem('isAuthenticated') === 'true' ? (
              <button 
                onClick={() => { localStorage.removeItem('isAuthenticated'); navigate('/login'); setMobileMenuOpen(false); }}
                className="flex items-center gap-3 px-4 py-3 rounded-xl text-base font-semibold text-red-400 hover:text-red-300 hover:bg-red-500/10 transition-all mt-2"
              >
                <LogOut className="w-5 h-5" />
                Sign Out
              </button>
            ) : (
              <Link 
                to="/login"
                onClick={() => setMobileMenuOpen(false)}
                className="flex items-center justify-center w-full px-4 py-3 rounded-xl text-base font-bold text-[#050B18] bg-gradient-to-r from-emerald-400 to-cyan-500 mt-2"
              >
                Sign In
              </Link>
            )}
          </div>
        </div>
      )}
      <style>{`
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(-10px); }
          to { opacity: 1; transform: translateY(0); }
        }
      `}</style>
    </nav>
  );
}
